deleted_at IS NULL
AND region = #{q.region}
AND protocol = #{q.protocol}
AND source LIKE CONCAT('%', #{q.source}, '%')

    AND (
        host LIKE CONCAT('%', #{q.keyword}, '%')
        OR username LIKE CONCAT('%', #{q.keyword}, '%')
        OR source LIKE CONCAT('%', #{q.keyword}, '%')
        OR region LIKE CONCAT('%', #{q.keyword}, '%')
    )

deleted_at IS NULL
AND TRIM(region) = #{region}
AND status = #{q.status}
AND protocol = #{q.protocol}
AND allocation_mode = #{q.allocationMode}
AND source LIKE CONCAT('%', #{q.source}, '%')

    AND (
        host LIKE CONCAT('%', #{q.keyword}, '%')
        OR username LIKE CONCAT('%', #{q.keyword}, '%')
        OR source LIKE CONCAT('%', #{q.keyword}, '%')
        OR CONCAT(host, ':', port) LIKE CONCAT('%', #{q.keyword}, '%')
    )


    AND (
        host LIKE CONCAT('%', #{q.ipKeyword}, '%')
        OR CONCAT(host, ':', port) LIKE CONCAT('%', #{q.ipKeyword}, '%')
    )


    AND CAST(bound_account_id AS CHAR) LIKE CONCAT('%', #{q.accountKeyword}, '%')

