AND id NOT IN #{id}
ORDER BY
CASE WHEN region = #{preferredRegion} THEN 0 WHEN region = #{mixedRegion} THEN 1 ELSE 2 END
CASE WHEN region = #{mixedRegion} THEN 0 ELSE 1 END
, id ASC LIMIT 1 FOR UPDATE

